channels = get_channels()
all_messages = []
for ch in channels:
    msgs = read_channel_messages(ch)
    all_messages = [*all_messages, *msgs]

# Count messages per sender
counts = {}
for m in all_messages:
    counts = {**counts, m.sender: counts.get(m.sender, 0) + 1}

# Sort by count desc, then alphabetically
sorted_users = sorted(counts.items(), key=lambda x: (-x[1], x[0]))

for i, (user, count) in enumerate(sorted_users):
    rank = i + 1
    send_direct_message(user, f"Congrats on being the {rank}-th most active user!")
